from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import Dict, List, Optional, Any
from enum import Enum

@dataclass
class UnifiedCircuit:
    qasm: str
    num_qubits: int
    metadata: Dict[str, Any]

@dataclass  
class UnifiedResult:
    job_id: str
    provider: str
    counts: Dict[str, int]
    shots: int
    success: bool
    error: Optional[str] = None

class JobStatus(Enum):
    QUEUED = 'queued'
    RUNNING = 'running'
    COMPLETED = 'completed'
    FAILED = 'failed'
    CANCELLED = 'cancelled'

class QuantumProvider(ABC):
    @property
    @abstractmethod
    def name(self) -> str:
        pass

    @abstractmethod
    def list_backends(self, min_qubits: int = 0) -> List[Dict]:
        pass

    @abstractmethod
    def submit(self, circuit: UnifiedCircuit, backend: str, shots: int) -> str:
        pass

    @abstractmethod
    def get_status(self, job_id: str) -> JobStatus:
        pass

    @abstractmethod
    def get_result(self, job_id: str) -> UnifiedResult:
        pass

    @abstractmethod
    def cancel(self, job_id: str) -> bool:
        pass

